/* GIMPLE pass that counts basic blocks per function.
   Copyright (C) 2024 Free Software Foundation, Inc.

This file is part of GCC.

GCC is free software; you can redistribute it and/or modify it under
the terms of the GNU General Public License as published by the Free
Software Foundation; either version 3, or (at your option) any later
version.

GCC is distributed in the hope that it will be useful, but WITHOUT ANY
WARRANTY; without even the implied warranty of MERCHANTABILITY or
FITNESS FOR A PARTICULAR PURPOSE.  See the GNU General Public License
for more details.

You should have received a copy of the GNU General Public License
along with GCC; see the file COPYING3.  If not see
<http://www.gnu.org/licenses/>.  */

/* This pass counts the number of basic blocks in each function and
   reports the result via dump_file when dumping is enabled.  It is a
   minimal, read-only GIMPLE pass that does not modify the IR.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "basic-block.h"

namespace {

/* pass_data for the basic-block counting pass.  The pass name starts
   without a star so that a dump file is produced when -fdump-tree-count_bbs
   is requested.  No SSA or CFG properties are consumed or produced, and
   no TODO flags are needed because the pass is purely analytical.  */

const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS,		/* type */
  "count_bbs",		/* name */
  OPTGROUP_NONE,	/* optinfo_flags */
  TV_NONE,		/* tv_id */
  PROP_cfg,		/* properties_required */
  0,			/* properties_provided */
  0,			/* properties_destroyed */
  0,			/* todo_flags_start */
  0,			/* todo_flags_finish */
};

/* The pass class.  gate() always returns true so the pass runs for
   every function.  execute() counts basic blocks and writes the result
   to dump_file when dumping is active.  */

class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {}

  /* opt_pass methods: */
  bool gate (function *) final override { return true; }
  unsigned int execute (function *fun) final override;
}; // class pass_count_bbs

/* Count the basic blocks in FUN and report via dump_file.  */

unsigned int
pass_count_bbs::execute (function *fun)
{
  int count = 0;
  basic_block bb;

  /* Walk every real basic block (excludes ENTRY/EXIT pseudo-blocks).  */
  FOR_EACH_BB_FN (bb, fun)
    count++;

  if (dump_file)
    fprintf (dump_file,
	     "Function %s: %d basic block(s)\n",
	     current_function_name (), count);

  /* This pass does not modify the IR, so return 0 (no pending TODOs).  */
  return 0;
}

} // anon namespace

/* Factory function used by the pass manager to create an instance of
   pass_count_bbs.  Declared in gcc/tree-pass.h.  */

gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}
